/**
 * Initializes the OpenTelemetry implementations for tracing and metrics.
 * @typedef {Object} OTel
 * @property {NodeTracerProvider} tracerProvider - The initialized tracer provider.
 * @property {MeterProvider} meterProvider - The initialized meter provider.
 *
 * @returns {OTel} The initialized tracer and meter providers.
 */
declare const initializer: () => {
    tracerProvider: import("@opentelemetry/sdk-trace-node").NodeTracerProvider;
    meterProvider: import("@opentelemetry/sdk-metrics").MeterProvider;
};
export default initializer;
